import ast, os, sys

# 检查每个文件的 import 是否有潜在未使用的
for fname in sorted(os.listdir('src')):
    if not fname.endswith('.py') or fname == '__init__.py':
        continue
    path = os.path.join('src', fname)
    with open(path) as f:
        source = f.read()
    tree = ast.parse(source)

    # 收集所有 import 的名称
    imported_names = set()
    for node in ast.walk(tree):
        if isinstance(node, ast.Import):
            for alias in node.names:
                name = alias.asname or alias.name
                imported_names.add(name)
        elif isinstance(node, ast.ImportFrom):
            for alias in node.names:
                name = alias.asname or alias.name
                imported_names.add(name)

    # 在源码中检查每个 imported name 的使用次数
    for name in sorted(imported_names):
        # 跳过 _ 开头和常见的 re-export
        if name.startswith('_') or name == '*':
            continue
        # 计算名称在源码中出现的次数（粗略检查）
        count = source.count(name)
        # import 行本身会贡献 1-2 次，如果只有 1 次说明可能未使用
        if count <= 1:
            print(f'{fname}: possibly unused import: {name} (found {count} times)')
